@Service
public class MfaService {
    private static final int CODE_LENGTH = 16;
    private static final int CODE_COUNT = 10;
    private static final String CODE_CHARS = "ABCDEFGHIJKLMNOPQRSTUVWXYZ23456789";
    
    @Autowired
    private BackupCodeRepository backupCodeRepository;
    
    @Autowired
    private MfaUserSettingsRepository mfaUserSettingsRepository;
    
    @Autowired
    private PasswordEncoder passwordEncoder;
    
    public List<String> generateBackupCodes(Long userId) {
        List<String> codes = new ArrayList<>();
        SecureRandom random = new SecureRandom();
        
        for (int i = 0; i < CODE_COUNT; i++) {
            StringBuilder code = new StringBuilder();
            for (int j = 0; j < CODE_LENGTH; j++) {
                int index = random.nextInt(CODE_CHARS.length());
                code.append(CODE_CHARS.charAt(index));
            }
            codes.add(code.toString());
        }
        
        // Save codes to database
        List<BackupCode> backupCodes = codes.stream()
            .map(code -> new BackupCode(userId, code))
            .collect(java.util.stream.Collectors.toList());
            
        backupCodeRepository.saveAll(backupCodes);
        return codes;
    }
    
    public boolean verifyBackupCode(Long userId, String code) {
        Optional<BackupCode> backupCodeOpt = backupCodeRepository.findByCode(code);
        
        if (backupCodeOpt.isPresent()) {
            BackupCode backupCode = backupCodeOpt.get();
            
            if (!backupCode.getIsUsed() && backupCode.getUserId().equals(userId)) {
                backupCode.setIsUsed(true);
                backupCodeRepository.save(backupCode);
                return true;
            }
        }
        
        return false;
    }
    
    public void enableMfa(Long userId, String secretKey) {
        MfaUserSettings settings = mfaUserSettingsRepository.findByUserId(userId)
            .orElse(new MfaUserSettings());
            
        settings.setUserId(userId);
        settings.setSecretKey(secretKey);
        settings.setIsEnabled(true);
        settings.setUpdatedAt(java.time.LocalDateTime.now());
        
        mfaUserSettingsRepository.save(settings);
    }
    
    public void disableMfa(Long userId) {
        mfaUserSettingsRepository.deleteByUserId(userId);
        backupCodeRepository.deleteByUserId(userId);
    }
    
    public List<String> getActiveBackupCodes(Long userId) {
        List<BackupCode> codes = backupCodeRepository.findByUserIdAndIsUsed(userId, false);
        return codes.stream()
            .map(BackupCode::getCode)
            .collect(java.util.stream.Collectors.toList());
    }
}

@RestController
@RequestMapping("/api/mfa")
public class MfaController {
    @Autowired
    private MfaService mfaService;
    
    @PostMapping("/enable")
    public ResponseEntity<?> enableMfa(@RequestParam Long userId, 
                                     @RequestParam String secretKey) {
        try {
            mfaService.enableMfa(userId, secretKey);
            List<String> backupCodes = mfaService.generateBackupCodes(userId);
            return ResponseEntity.ok(backupCodes);
        } catch (Exception e) {
            return ResponseEntity.status(500).body("Error enabling MFA");
        }
    }
    
    @PostMapping("/disable")
    public ResponseEntity<?> disableMfa(@RequestParam Long userId) {
        try {
            mfaService.disableMfa(userId);
            return ResponseEntity.ok().build();
        } catch (Exception e) {
            return ResponseEntity.status(500).body("Error disabling MFA");
        }
    }
    
    @PostMapping("/verify-backup")
    public ResponseEntity<?> verifyBackupCode(@RequestParam Long userId,
                                            @RequestParam String code) {
        try {
            boolean isValid = mfaService.verifyBackupCode(userId, code);
            if (isValid) {
                return ResponseEntity.ok().build();
            } else {
                return ResponseEntity.status(401).body("Invalid backup code");
            }
        } catch (Exception e) {
            return ResponseEntity.status(500).body("Error verifying backup code");
        }
    }
    
    @GetMapping("/backup-codes")
    public ResponseEntity<?> getBackupCodes(@RequestParam Long userId) {
        try {
            List<String> codes = mfaService.getActiveBackupCodes(userId);
            return ResponseEntity.ok(codes);
        } catch (Exception e) {
            return ResponseEntity.status(500).body("Error retrieving backup codes");
        }
    }
}

